data: {"type": "text-start", "id": "45287988-4fb9-4d9a-8a12-cdd2f135e946"}

data: {"type": "text-delta", "id": "45287988-4fb9-4d9a-8a12-cdd2f135e946", "delta": "1. `psql -U postgres -c \"SELECT client_addr, state, sent_lsn, write_lsn, flush_lsn, replay_lsn, sync_state FROM pg_stat_replication;\"`\n2. `psql -U postgres -c \"SELECT pg_wal_lsn_diff(pg_current_wal_lsn(), replay_lsn) AS lag_bytes FROM pg_stat_replication WHERE state = 'streaming';\"`\n3. `psql -U postgres -c \"SELECT * FROM pg_stat_activity WHERE state = 'idle in transaction' AND query_start < NOW() - INTERVAL '5 minutes';\"`\n4. `psql -U postgres -c \"SELECT datname, numbackends, xact_commit, xact_rollback, blks_read, blks_hit FROM pg_stat_database WHERE datname NOT IN ('template0', 'template1', 'postgres');\" | grep -v \"^$\"`\n5. `psql -U postgres -c \"SELECT pg_size_pretty(pg_relation_size('pg_wal')) AS wal_size, count(*) FROM pg_stat_replication;\"`"}

data: {"type": "text-end", "id": "45287988-4fb9-4d9a-8a12-cdd2f135e946"}

